1	<?php
2	declare(strict_types=1);
3	
4	namespace app\service\security;
5	
6	class FieldMaskingService
7	{
8	    /**
9	     * Fields that require masking and which roles are exempt.
10	     * Roles listed here can see the unmasked value.
11	     */
12	    private const MASKING_POLICY = [
13	        'tax_id'           => ['administrator'],
14	        'tax_id_encrypted' => ['administrator'],
15	        'phone'            => ['administrator', 'auditor'],
16	        'password_hash'    => [],  // never shown to anyone
17	    ];
18	
19	    /**
20	     * Mask a value, showing only the last 4 characters.
21	     */
22	    public function mask(string $value, string $policy = 'default'): string
23	    {
24	        $length = mb_strlen($value);
25	        if ($length <= 4) {
26	            return str_repeat('*', $length);
27	        }
28	        return str_repeat('*', $length - 4) . mb_substr($value, -4);
29	    }
30	
31	    /**
32	     * Determine whether a field should be masked for the given roles.
33	     */
34	    public function shouldMask(string $field, array $userRoles): bool
35	    {
36	        if (!isset(self::MASKING_POLICY[$field])) {
37	            return false;
38	        }
39	
40	        $exemptRoles = self::MASKING_POLICY[$field];
41	        if (empty($exemptRoles)) {
42	            return true; // always mask (e.g. password_hash)
43	        }
44	
45	        return empty(array_intersect($userRoles, $exemptRoles));
46	    }
47	
48	    /**
49	     * Apply masking to an entire record's maskable fields.
50	     */
51	    public function applyMaskingToRecord(array $record, array $maskableFields, array $userRoles): array
52	    {
53	        foreach ($maskableFields as $field) {
54	            if (isset($record[$field]) && is_string($record[$field]) && $this->shouldMask($field, $userRoles)) {
55	                $record[$field] = $this->mask($record[$field]);
56	            }
57	        }
58	        return $record;
59	    }
60	}
