229	    /**
230	     * GET /api/v1/reports/runs
231	     *
232	     * List report runs with pagination.
233	     */
234	    public function listRuns(ReportService $reportService): Response
235	    {
236	        $userRoles = $this->request->roles ?? [];
237	        if (empty(array_intersect($userRoles, self::REPORT_ROLES))) {
238	            return $this->error('FORBIDDEN_ROLE', 'Report access requires analyst, finance, admin, or auditor role.', [], 403);
239	        }
240	
241	        $filters = [
242	            'definition_id' => $this->request->get('definition_id'),
