265	     *
266	     * Read a single report run.
267	     */
268	    public function readRun($id, ReportService $reportService): Response
269	    {
270	        $run = $reportService->getRun((int) $id);
271	
272	        if (!$run) {
273	            return $this->error('NOT_FOUND', 'Report run not found.', [], 404);
