285	    /**
286	     * Check if the current user is privileged (admin/auditor) or owns the definition.
287	     */
288	    private function isPrivilegedOrOwner(?array $definition): bool
289	    {
290	        if (!$definition) {
291	            return false;
292	        }
293	        $privileged = ['administrator', 'auditor'];
294	        if (!empty(array_intersect($this->request->roles, $privileged))) {
295	            return true;
296	        }
297	        return ((int) ($definition['created_by'] ?? 0)) === $this->request->userId;
298	    }
