300	    /**
301	     * GET /api/v1/reports/runs/:id/download
302	     *
303	     * Download the output of a completed report run.
304	     */
305	    public function download($id, CsvExportService $csvExportService, AuditService $auditService): Response
306	    {
307	        // Ownership check: verify the run's definition belongs to the user or user is privileged
308	        $run = \think\facade\Db::name('report_runs')->where('id', (int) $id)->find();
309	        if ($run) {
310	            $definition = \think\facade\Db::name('report_definitions')
311	                ->where('id', $run['definition_id'])
312	                ->find();
313	            $userRoles = $this->request->roles ?? [];
314	            $privilegedRoles = ['administrator', 'auditor'];
315	            if ($definition && empty(array_intersect($userRoles, $privilegedRoles))) {
316	                if (($definition['created_by'] ?? null) != $this->request->userId) {
317	                    return $this->error('NOT_FOUND', 'Report artifact not found.', [], 404);
318	                }
319	            }
320	        }
321	
322	        $artifactPath = $csvExportService->getArtifactPath((int) $id);
323	
324	        if (!$artifactPath || !file_exists($artifactPath)) {
325	            return $this->error('NOT_FOUND', 'Report artifact not found.', [], 404);
326	        }
327	
328	        $auditService->log(
329	            'report.download',
330	            $this->request->userId,
331	            $this->request->roles[0] ?? 'unknown',
332	            !empty($this->request->siteScopes) ? $this->request->siteScopes[0] : null,
333	            'report_run',
334	            (int) $id,
335	            $this->request->requestId,
336	            'Downloaded report run artifact'
337	        );
338	
339	        ExportLog::create([
340	            'actor_id'     => $this->request->userId,
341	            'site_id'      => !empty($this->request->siteScopes) ? $this->request->siteScopes[0] : null,
342	            'export_type'  => 'report_download',
343	            'record_count' => 0,
344	            'reason'       => 'Report run download',
345	            'request_id'   => $this->request->requestId,
346	        ]);
347	
348	        return download($artifactPath);
349	    }
