351	    /**
352	     * GET /api/v1/reports/export-csv
353	     *
354	     * Export report data as CSV.
355	     */
356	    public function exportCsv(
357	        CsvExportService $csvExportService,
358	        AuditService $auditService,
359	        FieldMaskingService $fieldMaskingService
360	    ): Response {
361	        $allowed = ['operations_analyst', 'finance_clerk', 'administrator'];
362	        if (empty(array_intersect($this->request->roles, $allowed))) {
363	            return $this->error('FORBIDDEN_ROLE', 'You do not have permission to export reports.', [], 403);
364	        }
365	
366	        $input = json_decode($this->request->getInput(), true) ?: [];
367	
368	        $type    = $input['type'] ?? '';
369	        $filters = $input['filters'] ?? [];
370	
371	        $allowedTypes = ['orders', 'participants', 'recipes', 'settlement_statements'];
372	        if (!in_array($type, $allowedTypes, true)) {
373	            return $this->error('VALIDATION_FAILED', 'Export type must be one of: ' . implode(', ', $allowedTypes), [], 422);
374	        }
375	
376	        $siteScopes = $this->request->siteScopes ?? [];
377	        $userRoles  = $this->request->roles ?? [];
378	
379	        // Query data server-side based on type and filters
380	        $query = Db::name($type);
381	
382	        // Apply site scope filtering
383	        if (!empty($siteScopes)) {
384	            $query->whereIn('site_id', $siteScopes);
385	        }
386	
387	        // Apply user-provided filters
388	        if (!empty($filters['date_from'])) {
389	            $query->where('created_at', '>=', $filters['date_from']);
390	        }
391	        if (!empty($filters['date_to'])) {
392	            $query->where('created_at', '<=', $filters['date_to']);
393	        }
394	        if (!empty($filters['status'])) {
395	            $query->where('status', $filters['status']);
396	        }
397	        if (!empty($filters['site_id']) && in_array($filters['site_id'], $siteScopes, true)) {
398	            $query->where('site_id', $filters['site_id']);
399	        }
400	
401	        $data = $query->select()->toArray();
402	
403	        if (empty($data)) {
404	            return $this->error('VALIDATION_FAILED', 'No data found for the given type and filters.', [], 422);
405	        }
406	
407	        // Determine columns from data keys
408	        $columns = array_keys($data[0]);
409	
410	        // Apply field masking via FieldMaskingService
411	        $sensitiveFields = ['phone', 'tax_id', 'tax_id_encrypted', 'password_hash', 'email', 'national_id', 'bank_account'];
412	        $maskableFields  = array_intersect($sensitiveFields, $columns);
413	
414	        $maskedData = array_map(function (array $row) use ($fieldMaskingService, $maskableFields, $userRoles) {
415	            return $fieldMaskingService->applyMaskingToRecord($row, $maskableFields, $userRoles);
416	        }, $data);
417	
418	        $filePath = $csvExportService->generateCsv($maskedData, $columns, []);
419	
420	        if (empty($filePath) || !file_exists($filePath)) {
421	            return $this->error('NOT_FOUND', 'Failed to generate CSV export.', [], 500);
422	        }
423	
424	        $recordCount = count($maskedData);
425	
426	        $auditService->log(
427	            'report.export_csv',
428	            $this->request->userId,
429	            $this->request->roles[0] ?? 'unknown',
430	            !empty($siteScopes) ? $siteScopes[0] : null,
431	            'csv_export',
432	            null,
433	            $this->request->requestId,
434	            "Server-side {$type} CSV export with {$recordCount} rows"
435	        );
436	
437	        ExportLog::create([
438	            'actor_id'     => $this->request->userId,
439	            'site_id'      => !empty($siteScopes) ? $siteScopes[0] : null,
440	            'export_type'  => $type . '_csv',
441	            'record_count' => $recordCount,
442	            'reason'       => "Server-side {$type} CSV export",
443	            'request_id'   => $this->request->requestId,
444	        ]);
445	
446	        return download($filePath);
447	    }
448	}
