143	    /**
144	     * PUT /api/v1/recipe-versions/:id
145	     *
146	     * Update a draft version. $id is the VERSION id from the route.
147	     */
148	    public function updateVersion($id, RecipeService $recipeService): Response
149	    {
150	        $version = RecipeVersion::where('id', (int) $id)->find();
151	
152	        if (!$version) {
153	            return $this->error('NOT_FOUND', 'Version not found.', [], 404);
154	        }
155	
156	        // Site scope check via the parent recipe
157	        $recipe = $recipeService->find((int) $version->recipe_id, $this->request->siteScopes);
158	        if (!$recipe) {
159	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
160	        }
161	
162	        $input = json_decode($this->request->getInput(), true) ?: [];
163	
164	        try {
165	            validate(RecipeVersionValidate::class)->check($input);
166	        } catch (ValidateException $e) {
167	            return $this->error('VALIDATION_FAILED', $e->getMessage(), [], 422);
168	        }
169	
170	        // Validate ingredients if provided
171	        if (!empty($input['ingredients']) && is_array($input['ingredients'])) {
172	            $ingredientError = \app\validate\RecipeVersionValidate::validateIngredients($input['ingredients']);
173	            if ($ingredientError) {
174	                return $this->error('VALIDATION_FAILED', $ingredientError, [], 422);
175	            }
176	        }
177	
178	        if ($version->status !== 'draft') {
179	            return $this->error('WORKFLOW_CONFLICT', 'Only draft versions can be updated.', [], 409);
180	        }
181	
182	        // Update steps as structured data in recipe_steps table
183	        if (!empty($input['steps']) && is_array($input['steps'])) {
184	            \think\facade\Db::name('recipe_steps')->where('version_id', (int)$id)->delete();
185	            foreach ($input['steps'] as $i => $step) {
186	                \think\facade\Db::name('recipe_steps')->insert([
187	                    'version_id' => (int)$id,
188	                    'step_number' => $i + 1,
189	                    'instruction' => $step['instruction'] ?? '',
190	                    'duration_minutes' => $step['duration_minutes'] ?? null,
191	                    'created_at' => date('Y-m-d H:i:s'),
192	                ]);
193	            }
194	        }
195	
196	        $version->save([
197	            'content_json' => $input['content_json'] ?? $version->content_json,
198	            'total_time'   => $input['total_time'] ?? $version->total_time,
199	            'difficulty'   => $input['difficulty'] ?? $version->difficulty,
200	            'prep_time'    => $input['prep_time'] ?? $version->prep_time,
201	            'cook_time'    => $input['cook_time'] ?? $version->cook_time,
202	        ]);
203	
204	        return $this->success([
205	            'version_id' => (int) $id,
206	            'message'    => 'Version updated.',
207	        ]);
208	    }
