246	    /**
247	     * GET /api/v1/recipe-versions/:id/diff
248	     *
249	     * Show the diff between this version and the previous version.
250	     * $id is the VERSION id from the route.
251	     */
252	    public function diff($id, RecipeService $recipeService): Response
253	    {
254	        $version = RecipeVersion::where('id', (int) $id)->find();
255	
256	        if (!$version) {
257	            return $this->error('NOT_FOUND', 'Version not found.', [], 404);
258	        }
259	
260	        // Site scope check via the parent recipe
261	        $recipe = $recipeService->find((int) $version->recipe_id, $this->request->siteScopes);
262	        if (!$recipe) {
263	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
264	        }
265	
266	        $current = $version->toArray();
267	
268	        // Get the previous version of the same recipe
269	        $previous = RecipeVersion::where('recipe_id', (int) $version->recipe_id)
270	            ->where('version_number', '<', $version->version_number)
271	            ->order('version_number', 'desc')
272	            ->find();
273	
274	        if (!$previous) {
275	            return $this->success([
276	                'version_id' => (int) $id,
277	                'changes'    => [],
278	                'message'    => 'No previous version to compare.',
279	            ]);
280	        }
281	
282	        $previousData = $previous->toArray();
283	        $changes      = [];
284	
285	        $currentContent  = json_decode($current['content_json'] ?? '[]', true) ?: [];
286	        $previousContent = json_decode($previousData['content_json'] ?? '[]', true) ?: [];
287	
288	        foreach (['total_time', 'difficulty', 'prep_time', 'cook_time'] as $field) {
289	            if (($current[$field] ?? null) !== ($previousData[$field] ?? null)) {
290	                $changes[] = [
291	                    'field' => $field,
292	                    'old'   => $previousData[$field] ?? null,
293	                    'new'   => $current[$field] ?? null,
294	                ];
295	            }
296	        }
297	
298	        if ($currentContent !== $previousContent) {
299	            $changes[] = [
300	                'field' => 'steps',
301	                'old'   => $previousContent,
302	                'new'   => $currentContent,
303	            ];
304	        }
305	
306	        return $this->success([
307	            'version_id'       => (int) $id,
308	            'current_version'  => $current['version_number'],
309	            'previous_version' => $previousData['version_number'],
310	            'changes'          => $changes,
311	        ]);
312	    }
