172	
173	    /**
174	     * Request an asynchronous data refresh for the given scope.
175	     * Rate limited to 5 requests per hour per user.
176	     *
177	     * @param int   $userId
178	     * @param array $scope  Refresh scope parameters (site_id).
179	     * @return array Refresh request record including request ID and status.
180	     */
181	    public function requestRefresh(int $userId, array $scope): array
182	    {
183	        $oneHourAgo = date('Y-m-d H:i:s', strtotime('-1 hour'));
184	        $recentCount = Db::table('analytics_refresh_requests')
185	            ->where('user_id', $userId)
186	            ->where('created_at', '>=', $oneHourAgo)
187	            ->count();
188	
189	        if ($recentCount >= 5) {
190	            throw new ValidateException('Rate limit exceeded. Maximum 5 refresh requests per hour.');
191	        }
192	
193	        $now = date('Y-m-d H:i:s');
194	        $id = Db::table('analytics_refresh_requests')->insertGetId([
195	            'user_id' => $userId,
196	            'site_id' => $scope['site_id'] ?? null,
197	            'status' => 'requested',
198	            'created_at' => $now,
199	        ]);
200	
201	        return [
202	            'id' => $id,
203	            'user_id' => $userId,
204	            'site_id' => $scope['site_id'] ?? null,
205	            'status' => 'requested',
206	            'created_at' => $now,
207	        ];
208	    }
209	
210	    /**
211	     * Get the status of a previously requested refresh.
212	     *
213	     * @param int $requestId
214	     * @return array|null Refresh status or null if not found.
215	     */
216	    public function getRefreshStatus(int $requestId): ?array
217	    {
218	        $record = Db::table('analytics_refresh_requests')
219	            ->where('id', $requestId)
220	            ->find();
221	
222	        return $record ?: null;
223	    }
224	}
