205	    private function getAnyVersionId(array $session): ?int
206	    {
207	        $r = $this->authenticatedRequest('GET', '/api/v1/recipes', $session);
208	        $items = $r['body']['data']['items'] ?? [];
209	        if (empty($items)) return null;
210	        $rd = $this->authenticatedRequest('GET', '/api/v1/recipes/' . $items[0]['id'], $session);
211	        $versions = $rd['body']['data']['versions'] ?? [];
212	        return $versions ? (int)$versions[0]['id'] : null;
213	    }
214	
215	    private function doUpload(array $session, int $versionId): array
216	    {
217	        $tmp = tempnam(sys_get_temp_dir(), 'upload_');
218	        $img = imagecreatetruecolor(5, 5);
219	        $color = imagecolorallocate($img, rand(0, 255), rand(0, 255), rand(0, 255));
220	        imagefill($img, 0, 0, $color);
221	        imagepng($img, $tmp);
222	        imagedestroy($img);
223	
224	        $ch = curl_init('http://127.0.0.1:8080/api/v1/files/images');
225	        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
226	        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
227	        curl_setopt($ch, CURLOPT_POST, true);
228	        curl_setopt($ch, CURLOPT_COOKIEFILE, $session['cookie_file']);
229	        curl_setopt($ch, CURLOPT_COOKIEJAR, $session['cookie_file']);
230	        $headers = ['Accept: application/json'];
231	        if (!empty($session['csrf_token'])) $headers[] = 'X-CSRF-Token: ' . $session['csrf_token'];
232	        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
233	        curl_setopt($ch, CURLOPT_POSTFIELDS, [
234	            'file' => new \CURLFile($tmp, 'image/png', 'test.png'),
235	            'version_id' => (string)$versionId,
236	        ]);
237	        $response = curl_exec($ch);
238	        $code = curl_getinfo($ch, CURLINFO_HTTP_CODE);
239	        curl_close($ch);
240	        @unlink($tmp);
241	        return ['status' => $code, 'body' => json_decode($response ?: '', true) ?? [], 'raw' => $response];
242	    }
243	}
