2	declare(strict_types=1);
3	
4	namespace app\service\report;
5	
6	use think\facade\Db;
7	use think\exception\ValidateException;
8	
9	class ReportService
10	{
11	    private CsvExportService $csvExportService;
12	
13	    public function __construct(CsvExportService $csvExportService)
14	    {
15	        $this->csvExportService = $csvExportService;
16	    }
17	    /**
18	     * Create a new report definition.
19	     *
20	     * @param array $data   Report definition attributes (name, description, dimensions_json, filters_json, columns_json).
21	     * @param int   $userId Creating user ID.
22	     * @return array The created definition record.
23	     */
24	    public function createDefinition(array $data, int $userId): array
25	    {
26	        if (empty($data['name'])) {
27	            throw new ValidateException('Report name is required.');
28	        }
29	
30	        $now = date('Y-m-d H:i:s');
31	        $id = Db::table('report_definitions')->insertGetId([
32	            'name' => $data['name'],
33	            'description' => $data['description'] ?? null,
34	            'dimensions_json' => isset($data['dimensions_json']) ? (is_array($data['dimensions_json']) ? json_encode($data['dimensions_json']) : $data['dimensions_json']) : null,
35	            'filters_json' => isset($data['filters_json']) ? (is_array($data['filters_json']) ? json_encode($data['filters_json']) : $data['filters_json']) : null,
36	            'columns_json' => isset($data['columns_json']) ? (is_array($data['columns_json']) ? json_encode($data['columns_json']) : $data['columns_json']) : null,
37	            'created_by' => $userId,
38	            'created_at' => $now,
39	            'updated_at' => $now,
40	        ]);
41	
42	        return Db::table('report_definitions')->where('id', $id)->find();
43	    }
44	
45	    /**
46	     * Find a report definition by ID.
47	     *
48	     * @param int $id
49	     * @return array|null Definition data or null if not found.
50	     */
51	    public function findDefinition(int $id): ?array
52	    {
53	        $record = Db::table('report_definitions')->where('id', $id)->find();
54	        return $record ?: null;
55	    }
56	
57	    /**
58	     * Update an existing report definition.
59	     *
60	     * @param int   $id
61	     * @param array $data Updated attributes.
62	     * @return array The updated definition record.
63	     */
64	    public function updateDefinition(int $id, array $data): array
65	    {
66	        $existing = Db::table('report_definitions')->where('id', $id)->find();
67	        if (!$existing) {
68	            throw new ValidateException('Report definition not found.');
69	        }
70	
71	        $update = ['updated_at' => date('Y-m-d H:i:s')];
72	
73	        if (array_key_exists('name', $data)) {
74	            $update['name'] = $data['name'];
75	        }
76	        if (array_key_exists('description', $data)) {
77	            $update['description'] = $data['description'];
78	        }
79	        if (array_key_exists('dimensions_json', $data)) {
80	            $update['dimensions_json'] = is_array($data['dimensions_json']) ? json_encode($data['dimensions_json']) : $data['dimensions_json'];
81	        }
82	        if (array_key_exists('filters_json', $data)) {
83	            $update['filters_json'] = is_array($data['filters_json']) ? json_encode($data['filters_json']) : $data['filters_json'];
84	        }
85	        if (array_key_exists('columns_json', $data)) {
86	            $update['columns_json'] = is_array($data['columns_json']) ? json_encode($data['columns_json']) : $data['columns_json'];
87	        }
88	
89	        Db::table('report_definitions')->where('id', $id)->update($update);
90	
91	        return Db::table('report_definitions')->where('id', $id)->find();
92	    }
93	
94	    /**
95	     * Queue a report run for the given definition.
96	     *
97	     * @param int $definitionId
98	     * @param int $userId
99	     * @return array The created run record with status 'queued'.
100	     */
101	    public function queueRun(int $definitionId, int $userId): array
102	    {
103	        $definition = Db::table('report_definitions')->where('id', $definitionId)->find();
104	        if (!$definition) {
105	            throw new ValidateException('Report definition not found.');
106	        }
107	
108	        $now = date('Y-m-d H:i:s');
109	        $id = Db::table('report_runs')->insertGetId([
110	            'definition_id' => $definitionId,
111	            'status' => 'queued',
112	            'created_at' => $now,
113	        ]);
114	
115	        // Execute synchronously for the scaffold phase
116	        $this->executeRun($id);
117	
118	        return Db::table('report_runs')->where('id', $id)->find();
119	    }
120	
121	    /**
122	     * Execute a report run: query data, generate CSV, create artifact record.
123	     *
124	     * @param int $runId
125	     * @return void
126	     */
127	    public function executeRun(int $runId): void
128	    {
129	        $run = Db::table('report_runs')->where('id', $runId)->find();
130	        if (!$run) {
131	            throw new ValidateException('Report run not found.');
132	        }
133	
134	        $definition = Db::table('report_definitions')->where('id', $run['definition_id'])->find();
135	        if (!$definition) {
136	            Db::table('report_runs')->where('id', $runId)->update([
137	                'status' => 'failed',
138	                'completed_at' => date('Y-m-d H:i:s'),
139	            ]);
140	            return;
141	        }
142	
143	        Db::table('report_runs')->where('id', $runId)->update([
144	            'status' => 'running',
145	            'started_at' => date('Y-m-d H:i:s'),
146	        ]);
147	
148	        try {
149	            $dimensions = !empty($definition['dimensions_json'])
150	                ? json_decode($definition['dimensions_json'], true) : [];
151	            $filters = !empty($definition['filters_json'])
152	                ? json_decode($definition['filters_json'], true) : [];
153	            $columns = !empty($definition['columns_json'])
154	                ? json_decode($definition['columns_json'], true) : [];
155	
156	            $reportType = $dimensions['type'] ?? ($filters['type'] ?? 'general');
157	
158	            $data = $this->queryReportData($reportType, $dimensions, $filters);
159	
160	            $csvColumns = !empty($columns) ? $columns : (!empty($data) ? array_keys($data[0]) : []);
161	
162	            $filePath = $this->csvExportService->generateCsv($data, $csvColumns, []);
163	
164	            $now = date('Y-m-d H:i:s');
165	            $expiresAt = date('Y-m-d H:i:s', strtotime('+180 days'));
166	
167	            // report_artifacts schema: run_id, file_path, file_size, sha256_hash, created_at
168	            $fileSize = file_exists($filePath) ? filesize($filePath) : 0;
169	            $sha256 = file_exists($filePath) ? hash_file('sha256', $filePath) : '';
170	
171	            Db::table('report_artifacts')->insert([
172	                'run_id'      => $runId,
173	                'file_path'   => $filePath,
174	                'file_size'   => $fileSize,
175	                'sha256_hash' => $sha256,
176	                'created_at'  => $now,
177	            ]);
178	
179	            // report_runs schema: artifact_path, expires_at, started_at, completed_at
180	            Db::table('report_runs')->where('id', $runId)->update([
181	                'status'        => 'succeeded',
182	                'artifact_path' => $filePath,
183	                'expires_at'    => $expiresAt,
184	                'completed_at'  => $now,
185	            ]);
186	        } catch (\Throwable $e) {
187	            Db::table('report_runs')->where('id', $runId)->update([
188	                'status'       => 'failed',
189	                'completed_at' => date('Y-m-d H:i:s'),
190	            ]);
191	            throw $e;
192	        }
193	    }
194	
195	    /**
196	     * Query report data based on the report type and definition parameters.
197	     *
198	     * @param string $reportType
199	     * @param array  $dimensions
200	     * @param array  $filters
201	     * @return array
202	     */
203	    private function queryReportData(string $reportType, array $dimensions, array $filters): array
204	    {
205	        $query = null;
206	
207	        switch ($reportType) {
208	            case 'participation':
209	                $query = Db::table('participants')
210	                    ->field('site_id, COUNT(*) as participant_count')
211	                    ->group('site_id');
212	                break;
213	
214	            case 'retention':
215	                $query = Db::table('participants')
216	                    ->alias('p')
217	                    ->leftJoin('orders o', 'o.participant_id = p.id')
218	                    ->field('p.id, p.name, COUNT(o.id) as order_count, IF(COUNT(o.id) > 1, "repeat", "one-time") as participant_type')
219	                    ->group('p.id, p.name');
220	                break;
221	
222	            case 'pass_rate':
223	                $query = Db::table('recipes')
224	                    ->field('status, COUNT(*) as recipe_count, ROUND(COUNT(CASE WHEN status = "approved" THEN 1 END) * 100.0 / COUNT(*), 2) as approval_rate')
225	                    ->group('status');
226	                break;
227	
228	            case 'regional_distribution':
229	                $query = Db::table('orders')
230	                    ->alias('o')
231	                    ->leftJoin('participants p', 'p.id = o.participant_id')
232	                    ->field('o.site_id, COUNT(DISTINCT o.id) as order_count, COUNT(DISTINCT o.participant_id) as participant_count')
233	                    ->group('o.site_id');
234	                break;
235	
236	            default:
237	                // General report: determine table from dimensions or default to orders
238	                $table = $dimensions['table'] ?? 'orders';
239	                $allowedTables = ['orders', 'participants', 'recipes', 'settlement_statements'];
240	                if (!in_array($table, $allowedTables, true)) {
241	                    $table = 'orders';
242	                }
243	                $query = Db::table($table);
244	                break;
245	        }
246	
247	        // Apply common filters
248	        if (!empty($filters['site_id'])) {
249	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id' : 'site_id';
250	            $query->where($siteCol, $filters['site_id']);
251	        }
252	        if (!empty($filters['site_ids']) && is_array($filters['site_ids'])) {
253	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id' : 'site_id';
254	            $query->whereIn($siteCol, $filters['site_ids']);
255	        }
256	        if (!empty($filters['date_from'])) {
257	            $dateCol = in_array($reportType, ['retention']) ? 'p.created_at' : 'created_at';
258	            $query->where($dateCol, '>=', $filters['date_from']);
