24	    /**
25	     * Make an HTTP request to the running application.
26	     * With host networking, the app listens on 127.0.0.1:8080 both
27	     * from inside the container and from the host.
28	     */
29	    protected function httpRequest(string $method, string $path, array $data = [], array $headers = []): array
30	    {
31	        $url = 'http://127.0.0.1:8080' . $path;
32	
33	        $ch = curl_init();
34	        curl_setopt($ch, CURLOPT_URL, $url);
35	        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
36	        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
37	        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, strtoupper($method));
38	        curl_setopt($ch, CURLOPT_HTTPHEADER, array_merge(
39	            ['Content-Type: application/json', 'Accept: application/json'],
40	            $headers
41	        ));
42	
43	        if (!empty($data) && in_array(strtoupper($method), ['POST', 'PUT', 'PATCH'])) {
44	            curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
45	        }
46	
47	        $response = curl_exec($ch);
48	        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
49	        curl_close($ch);
50	
51	        return [
52	            'status' => $httpCode,
53	            'body' => json_decode($response ?: '', true) ?? [],
54	            'raw' => $response,
55	        ];
56	    }
