2	declare(strict_types=1);
3	
4	namespace app\service\security;
5	
6	class FieldMaskingService
7	{
8	    /**
9	     * Fields that require masking and which roles are exempt.
10	     * Roles listed here can see the unmasked value.
11	     */
12	    private const MASKING_POLICY = [
13	        'tax_id'           => ['administrator'],
14	        'tax_id_encrypted' => ['administrator'],
15	        'phone'            => ['administrator', 'auditor'],
16	        'password_hash'    => [],  // never shown to anyone
17	        'email'            => ['administrator', 'auditor'],
18	        'national_id'      => ['administrator'],
19	        'bank_account'     => ['administrator'],
20	    ];
21	
22	    /**
23	     * Mask a value, showing only the last 4 characters.
24	     */
25	    public function mask(string $value, string $policy = 'default'): string
26	    {
27	        $length = mb_strlen($value);
28	        if ($length <= 4) {
29	            return str_repeat('*', $length);
30	        }
31	        return str_repeat('*', $length - 4) . mb_substr($value, -4);
32	    }
33	
34	    /**
35	     * Determine whether a field should be masked for the given roles.
36	     */
37	    public function shouldMask(string $field, array $userRoles): bool
38	    {
39	        if (!isset(self::MASKING_POLICY[$field])) {
40	            return false;
41	        }
42	
43	        $exemptRoles = self::MASKING_POLICY[$field];
44	        if (empty($exemptRoles)) {
45	            return true; // always mask (e.g. password_hash)
46	        }
47	
48	        return empty(array_intersect($userRoles, $exemptRoles));
49	    }
50	
51	    /**
52	     * Apply masking to an entire record's maskable fields.
53	     */
54	    public function applyMaskingToRecord(array $record, array $maskableFields, array $userRoles): array
55	    {
56	        foreach ($maskableFields as $field) {
57	            if (isset($record[$field]) && is_string($record[$field]) && $this->shouldMask($field, $userRoles)) {
58	                $record[$field] = $this->mask($record[$field]);
59	            }
60	        }
61	        return $record;
62	    }
63	}
